"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"

// -------------------------------------------------------------------------
// Root context — shared by every sub-component inside <Stepper>
// -------------------------------------------------------------------------

interface StepperContextValue {
  activeStep: number
  setActiveStep: (step: number) => void
  totalSteps: number
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper() {
  const ctx = React.useContext(StepperContext)
  if (!ctx) throw new Error("useStepper must be used within a <Stepper>")
  return ctx
}

// -------------------------------------------------------------------------
// Per-item context — set by <StepperItem>, read by its children
// -------------------------------------------------------------------------

interface StepperItemContextValue {
  step: number
  state: "active" | "completed" | "inactive"
}

const StepperItemContext = React.createContext<StepperItemContextValue | null>(
  null
)

function useStepperItem() {
  const ctx = React.useContext(StepperItemContext)
  if (!ctx)
    throw new Error("useStepperItem must be used within a <StepperItem>")
  return ctx
}

// -------------------------------------------------------------------------
// Stepper — root container + provider
// -------------------------------------------------------------------------

interface StepperProps extends Omit<React.ComponentProps<"div">, "step"> {
  /** Controlled active step (1-indexed). */
  step?: number
  /** Initial active step for uncontrolled usage (default: 1). */
  defaultStep?: number
  /** Called whenever the active step changes. */
  onStepChange?: (step: number) => void
  /** Total number of steps — used to clamp navigation. */
  totalSteps: number
  /** Layout orientation (default: "horizontal"). */
  orientation?: "horizontal" | "vertical"
}

function Stepper({
  step: stepProp,
  defaultStep = 1,
  onStepChange,
  totalSteps,
  orientation = "horizontal",
  className,
  children,
  ...props
}: StepperProps) {
  const [internalStep, setInternalStep] = React.useState(defaultStep)
  const controlled = stepProp !== undefined
  const activeStep = controlled ? stepProp : internalStep

  const setActiveStep = React.useCallback(
    (next: number) => {
      if (!controlled) setInternalStep(next)
      onStepChange?.(next)
    },
    [controlled, onStepChange]
  )

  return (
    <StepperContext.Provider
      value={{ activeStep, setActiveStep, totalSteps, orientation }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn("flex flex-col gap-4", className)}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// -------------------------------------------------------------------------
// StepperList — tablist wrapper for the row/column of step indicators
// -------------------------------------------------------------------------

function StepperList({ className, ...props }: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-list"
      role="tablist"
      aria-orientation={orientation}
      className={cn(
        "flex",
        orientation === "vertical" ? "flex-col" : "flex-row items-start",
        className
      )}
      {...props}
    />
  )
}

// -------------------------------------------------------------------------
// StepperItem — per-step wrapper; provides StepperItemContext to children
// -------------------------------------------------------------------------

interface StepperItemProps extends React.ComponentProps<"div"> {
  /** The 1-indexed position of this step. */
  step: number
}

function StepperItem({ step, className, children, ...props }: StepperItemProps) {
  const { activeStep } = useStepper()
  const state: "active" | "completed" | "inactive" =
    step === activeStep ? "active" : step < activeStep ? "completed" : "inactive"

  return (
    <StepperItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        className={cn("group/stepper-item flex", className)}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// -------------------------------------------------------------------------
// StepperTrigger — clickable circle button; shows check when completed
// -------------------------------------------------------------------------

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { setActiveStep } = useStepper()
  const { step, state } = useStepperItem()

  return (
    <button
      type="button"
      role="tab"
      data-slot="stepper-trigger"
      data-state={state}
      aria-selected={state === "active"}
      aria-current={state === "active" ? "step" : undefined}
      className={cn(
        "inline-flex size-8 shrink-0 cursor-pointer items-center justify-center rounded-full border-2 text-sm font-semibold transition-colors",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        "disabled:pointer-events-none disabled:opacity-50",
        "data-[state=active]:border-primary data-[state=active]:bg-primary data-[state=active]:text-primary-foreground",
        "data-[state=completed]:border-primary data-[state=completed]:bg-primary data-[state=completed]:text-primary-foreground",
        "data-[state=inactive]:border-muted-foreground/40 data-[state=inactive]:bg-background data-[state=inactive]:text-muted-foreground",
        className
      )}
      onClick={() => setActiveStep(step)}
      {...props}
    >
      {state === "completed" ? (
        <CheckIcon className="size-4" />
      ) : (
        children ?? step
      )}
    </button>
  )
}

// -------------------------------------------------------------------------
// StepperTitle — step label; dims when the step is inactive
// -------------------------------------------------------------------------

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn(
        "text-sm font-medium leading-none",
        "group-data-[state=inactive]/stepper-item:text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// -------------------------------------------------------------------------
// StepperDescription — optional sub-label beneath the title
// -------------------------------------------------------------------------

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

// -------------------------------------------------------------------------
// StepperSeparator — connector line; turns primary when the step is done
// -------------------------------------------------------------------------

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper-separator"
      aria-hidden
      className={cn(
        "bg-muted transition-colors",
        "group-data-[state=completed]/stepper-item:bg-primary",
        className
      )}
      {...props}
    />
  )
}

// -------------------------------------------------------------------------
// StepperPanel — content region; hidden via CSS when the step is inactive
// -------------------------------------------------------------------------

function StepperPanel({ className, ...props }: React.ComponentProps<"div">) {
  const { state } = useStepperItem()

  return (
    <div
      role="tabpanel"
      data-slot="stepper-panel"
      data-state={state}
      aria-hidden={state !== "active"}
      className={cn("data-[state=inactive]:hidden", className)}
      {...props}
