"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperDescription,
  StepperItem,
  StepperList,
  StepperPanel,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
  useStepper,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    step: 1,
    title: "Account",
    description: "Create your account",
    content:
      "Enter your email address and choose a secure password to get started.",
  },
  {
    step: 2,
    title: "Profile",
    description: "Set up your profile",
    content:
      "Add your name, avatar, and a short bio so others can find and recognise you.",
  },
  {
    step: 3,
    title: "Finish",
    description: "Review and confirm",
    content:
      "Everything looks good! Click Confirm to complete your onboarding.",
  },
]

function StepperNavigation() {
  const { activeStep, setActiveStep, totalSteps } = useStepper()

  return (
    <div className="flex justify-between pt-2">
      <Button
        variant="outline"
        size="sm"
        disabled={activeStep === 1}
        onClick={() => setActiveStep(activeStep - 1)}
      >
        Back
      </Button>
      <Button
        size="sm"
        disabled={activeStep === totalSteps}
        onClick={() => setActiveStep(activeStep + 1)}
      >
        {activeStep === totalSteps ? "Confirm" : "Continue"}
      </Button>
    </div>
  )
}

export default function StepperDemo() {
  return (
    <div className="w-full max-w-lg">
      <Stepper defaultStep={1} totalSteps={steps.length}>
        {/* ── Step indicators ── */}
        <StepperList className="w-full">
          {steps.map(({ step, title, description }, index) => (
            <StepperItem
              key={step}
              step={step}
              className="flex-1 flex-col items-start gap-2"
            >
              <div className="flex w-full items-center">
                <StepperTrigger />
                {index < steps.length - 1 && (
                  <StepperSeparator className="mx-2 h-0.5 flex-1" />
                )}
              </div>
              <div className="flex flex-col gap-0.5">
                <StepperTitle>{title}</StepperTitle>
                <StepperDescription>{description}</StepperDescription>
              </div>
            </StepperItem>
          ))}
        </StepperList>

        {/* ── Step panels ── */}
        {steps.map(({ step, title, content }) => (
          <StepperItem key={step} step={step}>
            <StepperPanel className="w-full rounded-lg border p-6">
              <p className="text-sm font-semibold">{title}</p>
              <p className="mt-1 text-sm text-muted-foreground">{content}</p>
            </StepperPanel>
          </StepperItem>
        ))}

        {/* ── Navigation ── */}
        <StepperNavigation />
      </Stepper>
    </div>
  )
}

